1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / processing fee ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // --- Base premiums for main items (with 5 G fee added) ---
15	  it.todo("single plain sword → premium 105 G (100 base + 5 fee)");
16	  it.todo("single plain amulet → premium 65 G (60 base + 5 fee)");
17	  it.todo("single plain staff → premium 85 G (80 base + 5 fee)");
18	  it.todo("single plain potion → premium 45 G (40 base + 5 fee)");
19	
20	  // --- Components base premiums ---
21	  it.todo("single rune → premium 30 G (25 base + 5 fee)");
22	  it.todo("2 runes → premium 55 G (50 base + 5 fee)");
23	  it.todo("3 runes → premium 65 G (60 base block + 5 fee)");
24	  it.todo("4 runes → premium 105 G (100 base, no block, + 5 fee)");
25	  it.todo("7 runes → premium 180 G (175 base + 5 fee)");
26	
27	  // --- Alike components ---
28	  it.todo("2 runes + 1 moonstone → premium 80 G (75 base, no block: different types, + 5 fee)");
29	  it.todo("3 runes + 3 moonstones → premium 125 G (120 base, two separate blocks, + 5 fee)");
30	
31	  // --- Cursed surcharge ---
32	  it.todo("cursed sword (no other modifiers, newcomer-no-fee-context) — see integration: 165 G");
33	
34	  // --- High enchantment threshold ---
35	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies (+30 G)");
36	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
37	  it.todo("cursed sword at enchantment 5 → both surcharges apply");
38	
39	  // --- Loyalty discount threshold ---
40	  it.todo("customer with exactly 2 years → loyalty discount applies (-20% of policy base)");
41	
42	  // --- Modifier scope on multi-item policies ---
43	  it.todo("policy with cursed sword + plain amulet → 210 G before further modifiers and fee (cursed surcharge applies only to cursed item's base premium)");
44	
45	  // --- Rounding in MHPCO's favor (premium up) ---
46	  it.todo("premium calculation that yields 197.5 G → final premium 198 G (rounded up)");
47	
48	  // --- Integration examples ---
49	  it.todo("newcomer with cursed sword (steel, ench 3), 0 years, no prior contract → premium 165 G");
50	  it.todo("long-standing customer's second contract: 3 years, cursed sword ench 7 → premium 160 G");
51	
52	  // --- Quote: unknown item type ---
53	  it.todo("quote with unknown item type → CLI exits non-zero with stderr error, no results on stdout");
54	
55	  // --- Claim: basic deductible & standard reimbursement ---
56	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
57	  it.todo("damage to a rune (no enchantment/material), damage 200 G → payout 100 G");
58	
59	  // --- Claim: enchantment ≥ 8 clause ---
60	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then -100)");
61	
62	  // --- Claim: dragon material clause ---
63	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full then -100)");
64	
65	  // --- Claim: both clauses, 50% wins ---
66	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% then -100)");
67	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause applies, then deductible)");
68	
69	  // --- Claim: deductible per damage event (multiple items) ---
70	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
71	
72	  // --- Multiple items of the same type ---
73	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
74	  it.todo("two-sword policy: dragon attack damages both swords → each entry has its own deductible");
75	  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero");
76	
77	  // --- Cap exhaustion ---
78	  it.todo("policy of sword + amulet → insurance sum 1600 G, cap 3200 G");
79	  it.todo("cursed sword (premium-modifiers don't raise cap) → cap 2000 G based on unmodified insurance value");
80	  it.todo("policy of sword + 3 runes → insurance sum 1750 G (block discount affects premium only)");
81	  it.todo("sword (cap 2000 G), two successive 1500 G claims → first payout 1400 G remaining 600; second payout 600 remaining 0");
82	
83	  // --- Rounding payout down ---
84	  it.todo("payout calculation that yields 350.5 G → final payout 350 G (rounded down)");
85	
86	  // --- Claim: error cases ---
87	  it.todo("claim references item not in policy → CLI exits non-zero with stderr error");
88	  it.todo("claim damage with negative amount → CLI exits non-zero with stderr error");
89	
90	  // --- CLI integration ---
